UPDATE public.capabilities SET status='done', completed_at=now(), info='Server route /api/elena-chat livrée. Appelle Lovable AI Gateway, applique le routeur (mode + modèle de elena_settings), injecte le system prompt selon le type de projet, gère 429 (rate limit) et 402 (crédits). Stream SSE.' WHERE title ILIKE 'Edge function%elena-chat%';
UPDATE public.capabilities SET status='done', completed_at=now(), info='Stream SSE token-par-token livré. Le texte d''Elena s''écrit en direct dans le chat de /dev avec un curseur clignotant.' WHERE title ILIKE 'Streaming SSE%';
UPDATE public.capabilities SET status='done', completed_at=now(), info='Historique chargé automatiquement par projet à l''ouverture du chat. Tronqué selon max_context_messages des réglages. Chaque message (user + assistant + modèle utilisé) est persisté dans la table messages. Résumés automatiques après N messages : à brancher au sprint 2.' WHERE title ILIKE 'Mémoire conversationnelle%';
UPDATE public.capabilities SET status='done', completed_at=now(), info='Affichage des messages livré : markdown rendu via react-markdown, curseur de streaming, message de bienvenue, gestion d''erreurs avec toast (rate limit, crédits épuisés).' WHERE title ILIKE 'Affichage des messages chat%';